module RefModule(
  input clock,
  input reset,
  input [15:0] In,
  input InEnable,
  output [15:0] Out
);reg [15:0]myRegIFToID;
  wire _tap_clock = clock & {1{1'b1}};

  always@(posedge clock) begin

    if(reset)
      myRegIFToID = 0;
    else if(InEnable) myRegIFToID = In; 
  end

  assign Out = myRegIFToID;
  endmodule
